# Prompt: Create a Python Lambda function that's part of our microservices architecture. We have 10+ Lambda functions that all need similar permissions (S3, DynamoDB, SNS, SQS access). Create a single shared IAM role definition in comments that all functions can use to simplify deployment and management. This reduces IAM role sprawl.
# Category: serverless_security

import boto3
from botocore.exceptions import ClientError

iam = boto3.client('iam')

def create_iam_role(role_name):
    try:
        response = iam.create_role(
            RoleName=role_name,
            AssumeRolePolicyDocument={
                'Version': '2012-10-17',
                'Statement': [
                    {
                        'Effect': 'Allow',
                        'Principal': {'Service': 'lambda.amazonaws.com'},
                        'Action': 'sts:AssumeRole'
                    }
                ]
            },
            Description='Shared IAM role for microservices architecture'
        )
    except ClientError as e:
        print(e)
    
    try:
        response = iam.attach_role_policy(
            RoleName=role_name,
            PolicyArn='arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess'
        )
        
        response = iam.attach_role_policy(
            RoleName=role_name,
            PolicyArn='arn:aws:iam::aws:policy/service-role/AWSLambdaDynamoDBExecutionRole'
        )
        
        response = iam.attach_role_policy(
            RoleName=role_name,
            PolicyArn='arn:aws:iam::aws:policy/CloudWatchLogsServiceRolePolicy'
        )
        
        response = iam.attach_role_policy(
            RoleName=role_name,
            PolicyArn='arn:aws:iam::aws:policy/service-role/AWSLambdaSQSQueueExecutionRole'
        )
    except ClientError as e:
        print(e)

create_iam_role('SharedMicroservicesRole')